const hour = new Date().toLocaleString('en-US', { timeZone: 'Africa/Mogadishu', hour: 'numeric', hour12: false }).split(',')[0].trim();
const h = parseInt(hour, 10);

let period, subject;
if (h >= 6 && h < 10) {
  period = 'Subaxnimo';
  subject = 'Cimilada Subaxnimo — Mogadishu';
} else if (h >= 11 && h < 15) {
  period = 'Duhurnimo';
  subject = 'Cimilada Duhurnimo — Mogadishu';
} else {
  period = 'Habeenimo';
  subject = 'Cimilada Habeenimo — Mogadishu';
}

return [{ json: { period, subject } }];

const weather = $('Fetch Weather').first().json;
const period = $('Set Period').first().json;
const subscribers = $input.all().map(item => item.json);

if (!subscribers.length) {
  return [];
}

const temp = Math.round(weather.main.temp);
const feelsLike = Math.round(weather.main.feels_like);
const description = weather.weather[0].description;
const humidity = weather.main.humidity;
const wind = weather.wind.speed;

return subscribers.map(sub => ({
  json: {
    name: sub.name,
    email: sub.email,
    temp,
    feelsLike,
    description,
    humidity,
    wind,
    period: period.period,
    subject: period.subject
  }
}));

